        "name": "Order Event Consumer",
        "responsibility": "Consumes order-placed events from the message broker and dispatches them to the Assignment Service. Handles retries and dead-letter routing.",
        "boundaries": "Stateless adapter between the order domain and the assignment domain."
      }
    ],
    "interfaces": [
      {
        "from": "Order Event Consumer",
        "to": "Assignment Service",
        "contract": "assignCourier(orderId, pickupLocation, deliveryLocation, priority) -> {courierId, estimatedPickupTime} | AssignmentFailure",
        "coupling_type": "async via message queue, sync internal call"
      },
      {
        "from": "Assignment Service",
        "to": "Courier Availability Cache",
        "contract": "getCandidates(location, radius, limit) -> Courier[] — returns pre-filtered candidates sorted by proximity score",
        "coupling_type": "in-process read, loose coupling"
