        "from": "Assignment Service",
        "to": "PostgreSQL",
        "contract": "BEGIN; SELECT FROM courier_availability WHERE courier_id = $1 AND status = 'available' FOR UPDATE SKIP LOCKED; INSERT INTO assignments(...); UPDATE courier_availability SET status = 'assigned'; COMMIT;",
