    {
      "area": "Availability cache implementation",
      "evolution_path": "Start with simple periodic DB polling (every 1-2 seconds). Can evolve to CDC (Change Data Capture) or push-based updates when scale demands it."
    }
  ],

  "rigidity_points": [
    {
