  "risks": [
    {
      "risk": "Database failover causes assignment unavailability for 5-30 seconds",
      "severity": "high",
      "mitigation": "Use a managed PostgreSQL with fast failover (Aurora: <1s, Patroni: 5-15s). Implement a client-side retry queue with exponential backoff so orders placed during failover are assigned shortly after recovery. Monitor failover frequency and duration."
    },
    {
      "risk": "Hot courier problem: popular couriers cause lock contention",
      "severity": "medium",
      "mitigation": "SKIP LOCKED eliminates blocking — concurrent requests simply try the next candidate. Ensure the candidate list has sufficient depth (top 5-10, not just top 1). Monitor lock skip rates."
    },
    {
      "risk": "Stale availability cache causes wasted lock attempts",
      "severity": "low",
      "mitigation": "Cache staleness only causes performance degradation (extra DB round-trips), never correctness issues. Monitor cache hit-to-successful-assignment ratio. Reduce polling interval if needed."
