      "src/assignment/candidate_ranker.ts — Isolated scoring/ranking strategy for courier candidates",
      "src/assignment/repository.ts — PostgreSQL repository with FOR UPDATE SKIP LOCKED transaction",
      "src/availability/cache.ts — In-memory courier availability cache (Phase 2)",
      "src/events/order_consumer.ts — Message queue consumer for order-placed events",
      "src/events/publisher.ts — Publishes courier-assigned and assignment-failed events",
      "migrations/001_create_courier_availability.sql — courier_availability table with unique constraint on active assignments",
      "migrations/002_create_assignments.sql — assignments table with status lifecycle"
