    "level": 55,
    "high_confidence_areas": [
      "PostgreSQL FOR UPDATE SKIP LOCKED is the right consistency mechanism for this scale and team size",
      "Single service (modular monolith) is correct for a 2-person team",
      "200ms latency target is achievable with this architecture",
      "In-memory cache for candidate pre-filtering is a sound optimization"
    ],
    "low_confidence_areas": [
      "The product team's actual tolerance for unavailability during DB failover — this fundamentally shapes the architecture",
      "Expected order volume and courier fleet size — affects whether the in-memory cache is needed in Phase 1",
      "Geographic distribution requirements — single-region vs multi-region changes the failover and latency story significantly"
    ],
    "assumptions": [
      "Single geographic region deployment (multi-region would dramatically complicate the consistency story)",
      "Courier fleet size in the hundreds to low thousands (not millions — that would require sharding)",
      "Order rate in the tens to low hundreds per second (PostgreSQL single-primary can handle this comfortably)",
      "The product team will choose consistency over availability during failover (Option A)",
      "Managed cloud infrastructure is available (managed PostgreSQL, managed message queue)"
    ]
  }
}
